<?php
namespace Zclone\Core;
use PDO;
final class Database { public PDO $pdo; public function __construct() { $host=Env::get('DB_HOST','127.0.0.1'); $port=Env::get('DB_PORT',3306); $db=Env::get('DB_DATABASE','zclone'); $dsn="mysql:host=$host;port=$port;dbname=$db;charset=utf8mb4"; $this->pdo=new PDO($dsn, Env::get('DB_USERNAME','zclone'), Env::get('DB_PASSWORD','zclone'), [PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION, PDO::ATTR_DEFAULT_FETCH_MODE=>PDO::FETCH_ASSOC, PDO::ATTR_EMULATE_PREPARES=>false]); } public function one(string $sql,array $p=[]): ?array { $s=$this->pdo->prepare($sql); $s->execute($p); $r=$s->fetch(); return $r?:null; } public function all(string $sql,array $p=[]): array { $s=$this->pdo->prepare($sql); $s->execute($p); return $s->fetchAll(); } public function exec(string $sql,array $p=[]): int { $s=$this->pdo->prepare($sql); $s->execute($p); return $s->rowCount(); } }
